import React, { useEffect, useState } from "react";
import Sidebar from "../../components/Sidebar";
import API from "../../api/api";

const FreelancerDashboard = () => {

  const user = JSON.parse(localStorage.getItem("user"));

  const [stats, setStats] = useState({
    totalProjects: 0,
    totalProposals: 0,
    acceptedProposals: 0,
    pendingProposals: 0
  });

  const [projects, setProjects] = useState([]);

  const [loading, setLoading] = useState(true);


  const fetchDashboard = async () => {

    try {

      const projectsRes = await API.get("/projects");

      const proposalsRes = await API.get("/proposals/freelancer/my-proposals");

      const proposals = proposalsRes.data;


      setStats({
        totalProjects: projectsRes.data.length,
        totalProposals: proposals.length,
        acceptedProposals:
          proposals.filter(p => p.status === "accepted").length,
        pendingProposals:
          proposals.filter(p => p.status === "pending").length
      });

      setProjects(projectsRes.data);

    } catch (err) {

      console.log(err);

    } finally {

      setLoading(false);

    }

  };


  useEffect(() => {

    fetchDashboard();

  }, []);



  // ✅ ADD THIS LOADING CONDITION

  if (loading) {

    return (

      <div className="flex">

        <Sidebar />

        <div className="ml-64 p-10 text-xl">

          Loading Dashboard...

        </div>

      </div>

    );

  }



  return (

    <div className="flex bg-gray-100 min-h-screen">

      <Sidebar />

      <div className="flex-1 ml-64 p-8">

        <h1 className="text-3xl font-bold mb-2">

          Welcome back, {user?.name} 👋

        </h1>

        <p className="text-gray-500 mb-6">

          Here's your freelancing overview

        </p>


        <div className="grid grid-cols-4 gap-6 mb-8">

          <div className="bg-white p-6 rounded-xl shadow">

            <p className="text-gray-500">Active Projects</p>

            <h2 className="text-3xl font-bold">

              {stats.totalProjects}

            </h2>

          </div>


          <div className="bg-white p-6 rounded-xl shadow">

            <p className="text-gray-500">Pending Proposals</p>

            <h2 className="text-3xl font-bold">

              {stats.pendingProposals}

            </h2>

          </div>

        </div>



        <h2 className="text-xl font-bold mb-4">

          Active Projects

        </h2>



        {projects.map((project) => (

          <div
            key={project.id}
            className="bg-white p-6 rounded-xl shadow mb-4"
          >

            <h3 className="font-bold text-lg">

              {project.title}

            </h3>

            <p className="text-gray-500">

              {project.description}

            </p>

            <p className="text-green-600 font-bold mt-2">

              ₹ {project.budget}

            </p>

          </div>

        ))}

      </div>

    </div>

  );

};

export default FreelancerDashboard;
